{"action":"created","comment":{"url":"https://api.github.com/repos/scipy/scipy/pulls/comments/1887371438","pull_request_review_id":2507064684,"id":1887371438,"node_id":"PRRC_kwDOABZIoc5wfwCu","diff_hunk":"@@ -62,14 +62,20 @@ void prolate_aswfa_nocv(T m, T n, T c, T x, T &s1f, T &s1d) {
